#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1e5+5;
int n,m,Q,rep[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read(),m=read(),Q=read();
    for(int i=1;i<=m;i++)rep[read()]=i;
    while(Q--){
        int x=read(),now=n-x+1;
        for(int i=n-x+1;i>=1;i--)
            if(now<=i+m-1&&i+m-1<=n)now=i+rep[now-i+1]-1;
        cout<<now<<"\n";
    }
    return 0;
}
